import React, { useState } from 'react';
import { View, Text, Button, Modal, Alert, FlatList } from 'react-native';

const ConfirmationModal = () => {
  const [modalVisible, setModalVisible] = useState(false);
  const [itemToDelete, setItemToDelete] = useState(null);

  const handleDeletePress = (item) => {
    setItemToDelete(item);
    setModalVisible(true);
  };

  const confirmDelete = () => {
    setModalVisible(false);
    Alert.alert('Supprimé', `${itemToDelete} a été supprimé.`);
    setItemToDelete(null);
  };

  return (
    <View>
      <FlatList
        data={['Tâche 1', 'Tâche 2', 'Tâche 3']}
        renderItem={({ item }) => (
          <View>
            <Text>{item}</Text>
            <Button title="Supprimer" onPress={() => handleDeletePress(item)} />
          </View>
        )}
        keyExtractor={(item) => item}
      />

      <Modal
        visible={modalVisible}
        transparent={true}
        animationType="slide"
      >
        <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <View style={{ backgroundColor: 'white', padding: 20, borderRadius: 10 }}>
            <Text>Supprimer {itemToDelete} ?</Text>
            <Button title="Confirmer" onPress={confirmDelete} />
            <Button title="Annuler" onPress={() => setModalVisible(false)} />
          </View>
        </View>
      </Modal>
    </View>
  );
};

export default ConfirmationModal;
