import React, { useState } from 'react';
import { View, Text, Button, Modal, TextInput, FlatList, Alert } from 'react-native';

const NoteApp = () => {
  const [modalVisible, setModalVisible] = useState(false);
  const [noteText, setNoteText] = useState('');
  const [notes, setNotes] = useState([]);

  const handleAddNote = () => {
    if (noteText.trim()) {
      setNotes([...notes, noteText]);
      Alert.alert('Succès', 'Note ajoutée');
      setNoteText('');
      setModalVisible(false);
    } else {
      Alert.alert('Erreur', 'Le champ ne peut pas être vide');
    }
  };

  return (
    <View style={{ flex: 1, padding: 20 }}>
      <Button title="Ajouter une note" onPress={() => setModalVisible(true)} />
      <FlatList
        data={notes}
        renderItem={({ item }) => <Text>- {item}</Text>}
        keyExtractor={(item, index) => index.toString()}
      />

      <Modal visible={modalVisible} animationType="fade" transparent>
        <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: '#000000aa' }}>
          <View style={{ backgroundColor: '#fff', padding: 20, borderRadius: 10, width: '80%' }}>
            <Text>Nouvelle note :</Text>
            <TextInput
              value={noteText}
              onChangeText={setNoteText}
              placeholder="Écrivez ici..."
              style={{ borderBottomWidth: 1, marginVertical: 10 }}
            />
            <Button title="Enregistrer" onPress={handleAddNote} />
            <Button title="Annuler" onPress={() => setModalVisible(false)} />
          </View>
        </View>
      </Modal>
    </View>
  );
};

export default NoteApp;
