import React, { useState } from 'react';
import { View, Text, Button, Modal, Platform, Alert } from 'react-native';

const CrossPlatformModal = () => {
  const [modalVisible, setModalVisible] = useState(false);

  const handleClose = () => {
    Alert.alert(
      'Confirmation',
      'Voulez-vous fermer la fenêtre ?',
      [
        { text: 'Annuler', style: 'cancel' },
        { text: 'Oui', onPress: () => setModalVisible(false) }
      ]
    );
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Button title="Ouvrir" onPress={() => setModalVisible(true)} />

      <Modal
        visible={modalVisible}
        transparent={Platform.OS === 'android' ? true : false}
        animationType={Platform.OS === 'ios' ? 'slide' : 'fade'}
        presentationStyle={Platform.OS === 'ios' ? 'pageSheet' : 'fullScreen'}
      >
        <View style={{
          flex: 1,
          backgroundColor: Platform.OS === 'android' ? 'rgba(0,0,0,0.8)' : 'white',
          justifyContent: 'center',
          alignItems: 'center'
        }}>
          <Text style={{ color: Platform.OS === 'android' ? 'white' : 'black' }}>
            Contenu spécifique
          </Text>
          <Button title="Fermer" onPress={handleClose} />
        </View>
      </Modal>
    </View>
  );
};

export default CrossPlatformModal;
